#[test]
fn test_entity_ordering() {
    // Test that entities are ordered correctly when encoding
    let mut entities = HashMap::new();
    entities.insert("run".to_string(), "1".to_string());
    entities.insert("task".to_string(), "rest".to_string());
    entities.insert("ses".to_string(), "01".to_string());
    entities.insert("sub".to_string(), "01".to_string());

    let bids_file = BidsFile {
        entities,
        suffix: "bold".to_string(),
        extension: "nii.gz".to_string(),
        path: None,
    };

    let filename = bids_file.to_filename();

    // Check order: sub should come before ses, ses before task, task before run
    let sub_pos = filename.find("sub-01").unwrap();
    let ses_pos = filename.find("ses-01").unwrap();
    let task_pos = filename.find("task-rest").unwrap();
    let run_pos = filename.find("run-1").unwrap();

    assert!(sub_pos < ses_pos);
    assert!(ses_pos < task_pos);
    assert!(task_pos < run_pos);
}

