     1→//! Mock BIDS dataset creation for testing
     2→//!
     3→//! This module provides utilities for creating temporary BIDS datasets
     4→//! for testing purposes, similar to the R bidser::create_mock_bids function.
     5→
     6→use std::fs;
     7→use std::path::{Path, PathBuf};
     8→use tempfile::TempDir;
     9→use serde_json::json;
    10→use std::io::Write;
    11→
    12→/// Represents a participant in the BIDS dataset
    13→#[derive(Debug, Clone)]
    14→pub struct Participant {
    15→    pub id: String,
    16→    pub age: Option<u32>,
    17→    pub sex: Option<String>,
    18→    pub handedness: Option<String>,
    19→}
    20→
    21→/// Represents a file to be created in the BIDS dataset
    22→#[derive(Debug, Clone)]
    23→pub struct FileSpec {
    24→    pub subject: String,
    25→    pub session: Option<String>,
    26→    pub datatype: String,  // "anat", "func", "dwi", etc.
    27→    pub task: Option<String>,
    28→    pub run: Option<String>,
    29→    pub suffix: String,
    30→    pub extension: String,
    31→    pub space: Option<String>,  // For derivatives
    32→    pub desc: Option<String>,   // For derivatives
    33→    pub is_derivative: bool,
    34→}
    35→
    36→/// Event data for functional runs
    37→#[derive(Debug, Clone)]
    38→pub struct EventData {
    39→    pub onset: Vec<f64>,
    40→    pub duration: Vec<f64>,
    41→    pub trial_type: Vec<String>,
    42→}
    43→
    44→/// Confound data for functional runs
    45→#[derive(Debug, Clone)]
    46→pub struct ConfoundData {
    47→    pub framewise_displacement: Vec<f64>,
    48→    pub trans_x: Vec<f64>,
    49→    pub trans_y: Vec<f64>,
    50→    pub trans_z: Vec<f64>,
    51→    pub rot_x: Vec<f64>,
    52→    pub rot_y: Vec<f64>,
    53→    pub rot_z: Vec<f64>,
    54→    pub csf: Vec<f64>,
    55→    pub white_matter: Vec<f64>,
    56→}
    57→
    58→/// Mock BIDS dataset builder
    59→pub struct MockBidsBuilder {
    60→    project_name: String,
    61→    participants: Vec<Participant>,
    62→    files: Vec<FileSpec>,
    63→    events: Vec<(FileSpec, EventData)>,
    64→    confounds: Vec<(FileSpec, ConfoundData)>,
    65→    dataset_description: Option<serde_json::Value>,
    66→}
    67→
    68→impl MockBidsBuilder {
    69→    /// Create a new mock BIDS dataset builder
    70→    pub fn new(project_name: &str) -> Self {
    71→        Self {
    72→            project_name: project_name.to_string(),
    73→            participants: Vec::new(),
    74→            files: Vec::new(),
    75→            events: Vec::new(),
    76→            confounds: Vec::new(),
    77→            dataset_description: None,
    78→        }
    79→    }
    80→
    81→    /// Add a participant
    82→    pub fn add_participant(mut self, participant: Participant) -> Self {
    83→        self.participants.push(participant);
    84→        self
    85→    }
    86→
    87→    /// Add multiple participants
    88→    pub fn add_participants(mut self, participants: Vec<Participant>) -> Self {
    89→        self.participants.extend(participants);
    90→        self
    91→    }
    92→
    93→    /// Add a file specification
    94→    pub fn add_file(mut self, file: FileSpec) -> Self {
    95→        self.files.push(file);
    96→        self
    97→    }
    98→
    99→    /// Add multiple file specifications
   100→    pub fn add_files(mut self, files: Vec<FileSpec>) -> Self {
   101→        self.files.extend(files);
   102→        self
   103→    }
   104→
   105→    /// Add event data for a functional run
   106→    pub fn add_events(mut self, file_spec: FileSpec, events: EventData) -> Self {
   107→        self.events.push((file_spec, events));
   108→        self
   109→    }
   110→
   111→    /// Add confound data for a functional run
   112→    pub fn add_confounds(mut self, file_spec: FileSpec, confounds: ConfoundData) -> Self {
   113→        self.confounds.push((file_spec, confounds));
   114→        self
   115→    }
   116→
   117→    /// Set dataset description
   118→    pub fn with_dataset_description(mut self, description: serde_json::Value) -> Self {
   119→        self.dataset_description = Some(description);
   120→        self
   121→    }
   122→
   123→    /// Build the mock BIDS dataset in a temporary directory
   124→    pub fn build(self) -> Result<TempDir, Box<dyn std::error::Error>> {
   125→        let temp_dir = TempDir::new()?;
   126→        let root_path = temp_dir.path();
   127→
   128→        // Create dataset_description.json
   129→        let dataset_desc = self.dataset_description.unwrap_or_else(|| {
   130→            json!({
   131→                "Name": self.project_name,
   132→                "BIDSVersion": "1.9.0",
   133→                "DatasetType": "raw",
   134→                "Authors": ["Test Author"],
   135→                "License": "CC0"
   136→            })
   137→        });
   138→        
   139→        let desc_path = root_path.join("dataset_description.json");
   140→        fs::write(&desc_path, serde_json::to_string_pretty(&dataset_desc)?)?;
   141→
   142→        // Create participants.tsv
   143→        self.create_participants_tsv(root_path)?;
   144→
   145→        // Create README
   146→        fs::write(root_path.join("README"), format!("# {}\n\nMock BIDS dataset for testing.", self.project_name))?;
   147→
   148→        // Create file structure
   149→        for file_spec in &self.files {
   150→            self.create_file(root_path, file_spec)?;
   151→        }
   152→
   153→        // Create event files
   154→        for (file_spec, event_data) in &self.events {
   155→            self.create_event_file(root_path, file_spec, event_data)?;
   156→        }
   157→
   158→        // Create confound files
   159→        for (file_spec, confound_data) in &self.confounds {
   160→            self.create_confound_file(root_path, file_spec, confound_data)?;
   161→        }
   162→
   163→        Ok(temp_dir)
   164→    }
   165→
   166→    /// Create participants.tsv file
   167→    fn create_participants_tsv(&self, root_path: &Path) -> Result<(), Box<dyn std::error::Error>> {
   168→        let mut content = String::from("participant_id\tage\tsex\thandedness\n");
   169→        
   170→        for participant in &self.participants {
   171→            content.push_str(&format!(
   172→                "{}\t{}\t{}\t{}\n",
   173→                participant.id,
   174→                participant.age.map_or("n/a".to_string(), |a| a.to_string()),
   175→                participant.sex.as_deref().unwrap_or("n/a"),
   176→                participant.handedness.as_deref().unwrap_or("n/a")
   177→            ));
   178→        }
   179→
   180→        fs::write(root_path.join("participants.tsv"), content)?;
   181→        Ok(())
   182→    }
   183→
   184→    /// Create a file based on FileSpec
   185→    fn create_file(&self, root_path: &Path, file_spec: &FileSpec) -> Result<(), Box<dyn std::error::Error>> {
   186→        let file_path = self.get_file_path(root_path, file_spec);
   187→        
   188→        // Create directory structure
   189→        if let Some(parent) = file_path.parent() {
   190→            fs::create_dir_all(parent)?;
   191→        }
   192→
   193→        // Create file based on type
   194→        match file_spec.extension.as_str() {
   195→            "nii.gz" | "nii" => {
   196→                // Create empty NIfTI file (just placeholder)
   197→                fs::write(&file_path, b"NIFTI_PLACEHOLDER")?;
   198→            }
   199→            "json" => {
   200→                // Create JSON sidecar
   201→                let json_content = self.create_json_sidecar(file_spec);
   202→                fs::write(&file_path, serde_json::to_string_pretty(&json_content)?)?;
   203→            }
   204→            "tsv" => {
   205→                // Create empty TSV file (will be populated by specific functions)
   206→                if !file_path.exists() {
   207→                    fs::write(&file_path, "")?;
   208→                }
   209→            }
   210→            _ => {
   211→                // Create empty file for other types
   212→                fs::write(&file_path, "")?;
   213→            }
   214→        }
   215→
   216→        Ok(())
   217→    }
   218→
   219→    /// Create event file
   220→    fn create_event_file(&self, root_path: &Path, file_spec: &FileSpec, event_data: &EventData) -> Result<(), Box<dyn std::error::Error>> {
   221→        let file_path = self.get_file_path(root_path, file_spec);
   222→        
   223→        // Create directory structure
   224→        if let Some(parent) = file_path.parent() {
   225→            fs::create_dir_all(parent)?;
   226→        }
   227→
   228→        // Create TSV content
   229→        let mut content = String::from("onset\tduration\ttrial_type\n");
   230→        for i in 0..event_data.onset.len() {
   231→            content.push_str(&format!(
   232→                "{}\t{}\t{}\n",
   233→                event_data.onset[i],
   234→                event_data.duration[i],
   235→                event_data.trial_type[i]
   236→            ));
   237→        }
   238→
   239→        fs::write(&file_path, content)?;
   240→        Ok(())
   241→    }
   242→
   243→    /// Create confound file
   244→    fn create_confound_file(&self, root_path: &Path, file_spec: &FileSpec, confound_data: &ConfoundData) -> Result<(), Box<dyn std::error::Error>> {
   245→        let file_path = self.get_file_path(root_path, file_spec);
   246→        
   247→        // Create directory structure
   248→        if let Some(parent) = file_path.parent() {
   249→            fs::create_dir_all(parent)?;
   250→        }
   251→
   252→        // Create TSV content
   253→        let mut content = String::from("framewise_displacement\ttrans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tcsf\twhite_matter\n");
   254→        
   255→        let n_timepoints = confound_data.framewise_displacement.len();
   256→        for i in 0..n_timepoints {
   257→            content.push_str(&format!(
   258→                "{}\t{}\t{}\t{}\t{}\t{}\t{}\t{}\t{}\n",
   259→                confound_data.framewise_displacement[i],
   260→                confound_data.trans_x[i],
   261→                confound_data.trans_y[i],
   262→                confound_data.trans_z[i],
   263→                confound_data.rot_x[i],
   264→                confound_data.rot_y[i],
   265→                confound_data.rot_z[i],
   266→                confound_data.csf[i],
   267→                confound_data.white_matter[i]
   268→            ));
   269→        }
   270→
   271→        fs::write(&file_path, content)?;
   272→        Ok(())
   273→    }
