   275→    /// Get the full file path for a FileSpec
   276→    fn get_file_path(&self, root_path: &Path, file_spec: &FileSpec) -> PathBuf {
   277→        let mut path = PathBuf::from(root_path);
   278→
   279→        // Add derivatives path if needed
   280→        if file_spec.is_derivative {
   281→            path.push("derivatives");
   282→            path.push("fmriprep");
   283→        }
