   285→        // Add subject directory
   286→        let sub_dir = if file_spec.subject.starts_with("sub-") {
   287→            file_spec.subject.clone()
   288→        } else {
   289→            format!("sub-{}", file_spec.subject)
   290→        };
   291→        path.push(&sub_dir);
   292→
   293→        // Add session directory if present
   294→        if let Some(ses) = &file_spec.session {
   295→            let ses_dir = if ses.starts_with("ses-") {
   296→                ses.clone()
   297→            } else {
   298→                format!("ses-{}", ses)
   299→            };
   300→            path.push(&ses_dir);
