        .regex(r"\.nii\.gz$")
        .execute()
        .expect("Failed to search for nifti files");

    assert!(nifti_files.len() > 0, "No nifti files found");
    for file in &nifti_files {
        assert!(file.path.as_ref().unwrap().to_string_lossy().ends_with(".nii.gz"));
    }

    // Test 3: Find files with 'T1w' in the name
    let t1w_files = project.search_files()
        .regex("T1w")
        .execute()
        .expect("Failed to search for T1w files");

    assert!(t1w_files.len() > 0, "No T1w files found");
    for file in &t1w_files {
        assert!(file.path.as_ref().unwrap().to_string_lossy().contains("T1w"));
    }

    // Test 4: Filter by subject
    let sub1001_files = project.search_files()
        .subject("1001")
        .execute()
        .expect("Failed to search for subject 1001 files");

    assert!(sub1001_files.len() > 0, "No files found for subject 1001");
    for file in &sub1001_files {
        assert_eq!(file.entities.get("sub"), Some(&"1001".to_string()));
    }

    let sub1002_files = project.search_files()
        .subject("1002")
        .execute()
        .expect("Failed to search for subject 1002 files");

    assert!(sub1002_files.len() > 0, "No files found for subject 1002");
    for file in &sub1002_files {
        assert_eq!(file.entities.get("sub"), Some(&"1002".to_string()));
    }

    // Ensure no overlap between subjects
    let sub1001_paths: Vec<_> = sub1001_files.iter()
        .filter_map(|f| f.path.as_ref())
        .collect();
    let sub1002_paths: Vec<_> = sub1002_files.iter()
        .filter_map(|f| f.path.as_ref())
        .collect();

    for path in &sub1001_paths {
        assert!(!sub1002_paths.contains(path), "File found in both subjects");
    }

    // Test 5: Filter by task
    let phoneme_files = project.search_files()
        .task("phoneme")
        .execute()
        .expect("Failed to search for phoneme task files");

    assert!(phoneme_files.len() > 0, "No phoneme task files found");
    for file in &phoneme_files {
        if file.entities.contains_key("task") {
            assert_eq!(file.entities.get("task"), Some(&"phoneme".to_string()));
        }
    }

    let rest_files = project.search_files()
        .task("rest")
        .execute()
        .expect("Failed to search for rest task files");

    assert!(rest_files.len() > 0, "No rest task files found");
    for file in &rest_files {
        if file.entities.contains_key("task") {
            assert_eq!(file.entities.get("task"), Some(&"rest".to_string()));
        }
    }

    // Test 6: Filter by run
    let run01_files = project.search_files()
        .run("01")
        .execute()
        .expect("Failed to search for run 01 files");

    assert!(run01_files.len() > 0, "No run 01 files found");
    for file in &run01_files {
        if file.entities.contains_key("run") {
            assert_eq!(file.entities.get("run"), Some(&"01".to_string()));
        }
    }

    let run02_files = project.search_files()
        .run("02")
        .execute()
        .expect("Failed to search for run 02 files");

    assert!(run02_files.len() > 0, "No run 02 files found");
    for file in &run02_files {
        if file.entities.contains_key("run") {
            assert_eq!(file.entities.get("run"), Some(&"02".to_string()));
        }
    }

    // Test 7: Combined filters
    let combined_files = project.search_files()
        .subject("1001")
        .task("phoneme")
        .run("01")
        .suffix("bold")
        .extension("nii.gz")
        .execute()
        .expect("Failed to search with combined filters");

    assert_eq!(combined_files.len(), 1, "Expected exactly 1 file with combined filters");
    let file = &combined_files[0];
    assert_eq!(file.entities.get("sub"), Some(&"1001".to_string()));
    assert_eq!(file.entities.get("task"), Some(&"phoneme".to_string()));
    assert_eq!(file.entities.get("run"), Some(&"01".to_string()));
    assert_eq!(file.suffix, "bold");
    assert_eq!(file.extension, "nii.gz");

    // Test 8: Handle no matches
    let no_match_files = project.search_files()
        .subject("9999")
        .execute();

    match no_match_files {
        Ok(files) => assert_eq!(files.len(), 0, "Expected no files for non-existent subject"),
        Err(_) => {} // Also acceptable
    }
}

