                self.participants
                    .iter()
                    .flat_map(|p| &p.sessions)
                    .collect::<std::collections::HashSet<_>>()
                    .len(),
            )
        } else {
            None
        };
        let n_tasks = self.tasks.len();
        let has_derivatives = self.has_derivatives;

