            .follow_links(true)
            .into_iter()
            .filter_map(|e| e.ok())
            .filter(|e| e.file_type().is_file())
        {
            let path = entry.path();
            let filename = path.file_name().and_then(|n| n.to_str()).unwrap_or("");

            // Count BIDS files (exclude hidden and system files)
            if !filename.starts_with('.')
                && !filename.starts_with('~')
                && filename.contains('_')
            {
