    /// Read all event files in the project
    pub fn read_events(&self) -> Result<Vec<crate::io::EventData>> {
        use crate::io::{EventsReader, BidsReader};

        let event_files = self.search_files()
            .suffix("events")
            .extension("tsv")
            .execute()?;

        let reader = EventsReader::new();
        let mut all_events = Vec::new();

        for file in event_files {
            match reader.read(&file) {
                Ok(mut event_data) => {
                    // Add subject info if available
                    if let Some(sub) = file.entities.get("sub") {
                        event_data.subject = sub.clone();
                    }
                    if let Some(ses) = file.entities.get("ses") {
                        event_data.session = Some(ses.clone());
                    }
                    if let Some(task) = file.entities.get("task") {
                        event_data.task = Some(task.clone());
                    }
                    if let Some(run) = file.entities.get("run") {
                        event_data.run = Some(run.clone());
                    }
                    all_events.push(event_data);
                }
                Err(e) => {
                    eprintln!("Warning: Failed to read event file {:?}: {}", file.path, e);
                }
            }
        }

        Ok(all_events)
    }

    /// Read event files for a specific subject
    pub fn read_events_for_subject(&self, subject: &str) -> Result<Vec<crate::io::EventData>> {
        use crate::io::{EventsReader, BidsReader};

        let event_files = self.search_files()
            .subject(subject)
