//! File discovery and search functionality
//!
//! This module provides tools for discovering and searching BIDS files
//! based on various criteria.

use std::collections::HashMap;
use std::path::PathBuf;

#[cfg(feature = "parallel")]
use rayon::prelude::*;

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::project::BidsProject;

/// Builder for constructing file search queries
#[derive(Debug, Clone)]
pub struct SearchBuilder<'a> {
    /// Reference to the BIDS project
    project: &'a BidsProject,
    /// Entity filters
    filters: HashMap<String, String>,
    /// File suffix filter
    suffix_filter: Option<String>,
    /// File extension filter
    extension_filter: Option<String>,
    /// File kind filter
    kind_filter: Option<String>,
    /// Whether to search in derivatives
    search_derivatives: bool,
    /// Whether to return full paths
    full_paths: bool,
    /// Whether to use strict matching (require all specified entities to exist)
    strict_mode: bool,
}

impl<'a> SearchBuilder<'a> {
    /// Create a new search builder
    pub fn new(project: &'a BidsProject) -> Self {
        Self {
            project,
            filters: HashMap::new(),
            suffix_filter: None,
            extension_filter: None,
            kind_filter: None,
            search_derivatives: false,
            full_paths: true,
        }
    }

    /// Filter by subject ID
    pub fn subject(mut self, subject: impl Into<String>) -> Self {
        self.filters.insert("sub".to_string(), subject.into());
        self
    }

    /// Filter by session ID
    pub fn session(mut self, session: impl Into<String>) -> Self {
        self.filters.insert("ses".to_string(), session.into());
        self
    }

    /// Filter by task
    pub fn task(mut self, task: impl Into<String>) -> Self {
        self.filters.insert("task".to_string(), task.into());
        self
    }

    /// Filter by run
    pub fn run(mut self, run: impl Into<String>) -> Self {
        self.filters.insert("run".to_string(), run.into());
        self
    }

    /// Filter by acquisition
    pub fn acquisition(mut self, acq: impl Into<String>) -> Self {
        self.filters.insert("acq".to_string(), acq.into());
        self
    }

    /// Filter by space
    pub fn space(mut self, space: impl Into<String>) -> Self {
        self.filters.insert("space".to_string(), space.into());
        self
    }

    /// Filter by description
    pub fn desc(mut self, desc: impl Into<String>) -> Self {
        self.filters.insert("desc".to_string(), desc.into());
        self
    }

    /// Filter by file suffix
    pub fn suffix(mut self, suffix: impl Into<String>) -> Self {
        self.suffix_filter = Some(suffix.into());
        self
    }

    /// Filter by file extension
    pub fn extension(mut self, extension: impl Into<String>) -> Self {
        self.extension_filter = Some(extension.into());
        self
    }

    /// Filter by datatype (e.g., "anat", "func", "dwi")
    pub fn datatype(mut self, datatype: impl Into<String>) -> Self {
        self.kind_filter = Some(datatype.into());
        self
    }

    /// Whether to search in derivatives
    pub fn in_derivatives(mut self, search_derivatives: bool) -> Self {
        self.search_derivatives = search_derivatives;
        self
    }

    /// Filter by file kind
    pub fn kind(mut self, kind: impl Into<String>) -> Self {
        self.kind_filter = Some(kind.into());
        self
    }

    /// Search in derivatives directory
    pub fn derivatives(mut self, search_derivatives: bool) -> Self {
        self.search_derivatives = search_derivatives;
        self
    }

    /// Return full paths vs relative paths
    pub fn full_paths(mut self, full_paths: bool) -> Self {
        self.full_paths = full_paths;
        self
    }

    /// Execute the search and return matching files
    pub fn collect(self) -> Result<Vec<BidsFile>> {
        use walkdir::WalkDir;
        use crate::parser::parse_filename;

        let mut results = Vec::new();
        let search_path = if self.search_derivatives {
            self.project.derivatives_path.as_ref()
                .ok_or_else(|| BidsError::unsupported_feature("No derivatives path available"))?
        } else {
            &self.project.path
        };

        // Walk through the directory structure
        for entry in WalkDir::new(search_path)
            .min_depth(1)
            .into_iter()
            .filter_map(|e| e.ok())
        {
            if entry.file_type().is_file() {
                let path = entry.path();

                // Skip non-BIDS files
                if let Some(filename) = path.file_name().and_then(|n| n.to_str()) {
                    // Parse the filename
                    if let Ok(parsed) = parse_filename(filename) {
                        // Apply filters
                        let mut matches = true;

                        // Check entity filters
                        for (key, value) in &self.filters {
                            if let Some(entity_value) = parsed.entities.get(key) {
                                if entity_value != value {
                                    matches = false;
                                    break;
                                }
                            } else {
                                matches = false;
                                break;
                            }
                        }

                        // Check suffix filter
                        if let Some(ref suffix) = self.suffix_filter {
                            if &parsed.suffix != suffix {
                                matches = false;
                            }
                        }

                        // Check extension filter
                        if let Some(ref ext) = self.extension_filter {
                            if &parsed.extension != ext {
                                matches = false;
                            }
                        }

                        // Check kind filter
                        if let Some(ref kind) = self.kind_filter {
                            if parsed.suffix != *kind {
                                matches = false;
                            }
                        }

                        if matches {
                            let file_path = if self.full_paths {
                                path.to_path_buf()
                            } else {
                                path.strip_prefix(&self.project.path)
                                    .unwrap_or(path)
                                    .to_path_buf()
                            };

                            // Determine if this is a derivative file
                            let is_derivative = path.components().any(|c| {
                                c.as_os_str() == "derivatives"
                            });

                            // Extract datatype from path (e.g., "anat", "func", "dwi")
                            let mut kind = parsed.kind.clone();
                            if kind.is_none() {
                                // Try to extract from path
                                for component in path.components() {
                                    let comp_str = component.as_os_str().to_string_lossy();
                                    if matches!(comp_str.as_ref(), "anat" | "func" | "dwi" | "fmap" | "perf" | "meg" | "eeg" | "ieeg" | "beh") {
                                        kind = Some(comp_str.to_string());
                                        break;
                                    }
                                }
                            }

                            // Apply datatype filter if set
                            if let Some(ref datatype_filter) = self.kind_filter {
                                if kind.as_ref() != Some(datatype_filter) {
                                    continue;
                                }
                            }

                            results.push(BidsFile {
                                path: file_path,
                                entities: parsed.entities,
                                suffix: parsed.suffix,
                                extension: parsed.extension,
                                kind,
                                modality: parsed.modality,
                                is_derivative,
                                metadata: HashMap::new(),
                            });
                        }
                    }
                }
            }
        }

        Ok(results)
    }

    /// Execute the search (alias for collect)
    #[allow(dead_code)]
    pub fn execute(self) -> Result<Vec<BidsFile>> {
        self.collect()
    }

    /// Execute the search in parallel (requires "parallel" feature)
    #[cfg(feature = "parallel")]
    pub fn collect_parallel(self) -> Result<Vec<BidsFile>> {
        use walkdir::WalkDir;
        use crate::parser::parse_filename;
        use std::sync::Mutex;

        let search_path = if self.search_derivatives {
            self.project.derivatives_path.as_ref()
                .ok_or_else(|| BidsError::unsupported_feature("No derivatives path available"))?
        } else {
            &self.project.path
        };

        // Collect all file paths first
        let paths: Vec<_> = WalkDir::new(search_path)
            .min_depth(1)
            .into_iter()
            .filter_map(|e| e.ok())
            .filter(|e| e.file_type().is_file())
            .map(|e| e.path().to_path_buf())
            .collect();

        // Process files in parallel
        let results = Mutex::new(Vec::new());

        paths.par_iter().for_each(|path| {
            if let Some(filename) = path.file_name().and_then(|n| n.to_str()) {
                if let Ok(parsed) = parse_filename(filename) {
                    let mut matches = true;

                    // Check entity filters
                    for (key, value) in &self.filters {
                        if let Some(entity_value) = parsed.entities.get(key) {
                            if entity_value != value {
                                matches = false;
                                break;
                            }
                        } else {
                            matches = false;
                            break;
                        }
                    }

                    // Check suffix filter
                    if let Some(ref suffix) = self.suffix_filter {
                        if &parsed.suffix != suffix {
                            matches = false;
                        }
                    }

                    // Check extension filter
                    if let Some(ref ext) = self.extension_filter {
                        if &parsed.extension != ext {
                            matches = false;
                        }
                    }

                    // Check kind filter
                    if let Some(ref kind) = self.kind_filter {
                        if parsed.suffix != *kind {
                            matches = false;
                        }
                    }

                    if matches {
                        let file_path = if self.full_paths {
                            path.clone()
                        } else {
                            path.strip_prefix(&self.project.path)
                                .unwrap_or(path)
                                .to_path_buf()
                        };

                        let bids_file = BidsFile {
                            path: file_path,
                            entities: parsed.entities,
                            suffix: parsed.suffix,
                            extension: parsed.extension,
                            metadata: HashMap::new(),
                        };

                        results.lock().unwrap().push(bids_file);
                    }
                }
            }
        });

        Ok(results.into_inner().unwrap())
    }

    /// Execute the search and return file paths
    #[allow(dead_code)]
    pub fn paths(self) -> Result<Vec<PathBuf>> {
        let files = self.collect()?;
        Ok(files.into_iter().map(|f| f.path).collect())
    }

    /// Execute the search and return the first matching file
    #[allow(dead_code)]
    pub fn first(self) -> Result<Option<BidsFile>> {
        let mut files = self.collect()?;
        Ok(files.pop())
    }

    /// Count matching files without loading them
    #[allow(dead_code)]
    pub fn count(self) -> Result<usize> {
        let files = self.collect()?;
        Ok(files.len())
    }

    /// Check if any files match the criteria
    #[allow(dead_code)]
    pub fn exists(self) -> Result<bool> {
        Ok(self.count()? > 0)
    }
}

/// Search for files in a BIDS project
#[allow(dead_code)]
pub fn search_files(
    project: &BidsProject,
    filters: &HashMap<String, String>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project);

    for (key, value) in filters {
        builder.filters.insert(key.clone(), value.clone());
    }

    builder.collect()
}

/// Find functional scans matching criteria
#[allow(dead_code)]
pub fn find_func_scans(
    project: &BidsProject,
    subject: Option<&str>,
    task: Option<&str>,
    run: Option<&str>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project).kind("bold");

    if let Some(sub) = subject {
        builder = builder.subject(sub);
    }

    if let Some(task) = task {
        builder = builder.task(task);
    }

    if let Some(run) = run {
        builder = builder.run(run);
    }

    builder.collect()
}

/// Find event files matching criteria
#[allow(dead_code)]
pub fn find_event_files(
    project: &BidsProject,
    subject: Option<&str>,
    task: Option<&str>,
    run: Option<&str>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project).suffix("events");

    if let Some(sub) = subject {
        builder = builder.subject(sub);
    }

    if let Some(task) = task {
        builder = builder.task(task);
    }

    if let Some(run) = run {
        builder = builder.run(run);
    }

    builder.collect()
}

